#!/usr/bin/env python3
import sys
def solve():
    data=sys.stdin.read().splitlines()
    if not data:
        return
    t=int(data[0].strip())
    idx=1
    out=[]
    for _ in range(t):
        S=data[idx] if idx<len(data) else ''
        idx+=1
        P=data[idx] if idx<len(data) else ''
        idx+=1
        if P=='':
            ans=len(S)
        else:
            ans=S.rfind(P)
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))
if __name__=='__main__':
    solve()

