let ptr=0;
const T=parseInt(input[ptr].trim(),10);
ptr++;
let results=[];
for(let tc=0;tc<T;++tc){
  const S=input[ptr]!==undefined?input[ptr]:'';
  ptr++;
  const P=input[ptr]!==undefined?input[ptr]:'';
  ptr++;
